// Helper to compute SHA-256 hash
function calculateHash(index: number, fromUser: string, toUser: string, amount: number, type: string, timestamp: string, previousHash: string): string {
  const content = `${index}|${fromUser}|${toUser}|${amount}|${type}|${timestamp}|${previousHash}`;
  return crypto.createHash("sha256").update(content).digest("hex");
}

// Helper to generate a digital signature
function generateSignature(hash: string): string {
  // Simple deterministic server signing using a simulated server private key
  const SECRET_KEY = "LEDGER_PLATFORM_SECURE_COIN_PRIVATE_KEY_2026";
  return crypto.createHash("sha256").update(hash + SECRET_KEY).digest("hex");
}

